import { useContext, useEffect, useState } from "react";
import { Navigate } from "react-router-dom";
import Cookies from "js-cookie";
import PermissionContext from "../context/PermissionContext";
import axios from "axios";

function ProtectedRoute({ children, requiredPermission, adminOnly }) {
  const { setPermissions } = useContext(PermissionContext);
  const { currentUser } = useContext(CurrentUserContext);
  const [loading, setLoading] = useState(true);
  const [isAllowed, setIsAllowed] = useState(false);

  const token = Cookies.get("adminToken");

  useEffect(() => {
    if (!token || !currentUser) {
      setLoading(false);
      return;
    }

    const fetchPermissions = async () => {
      try {
        const response = await axios.get(
          `${process.env.REACT_APP_API_BASE_URL}/admin/permissions/${currentUser.id}`,
          { headers: { Authorization: `Bearer ${token}` } }
        );

        const userPermissions = response.data.permissions || [];
        setPermissions(userPermissions);

        const allowed =
          (!adminOnly || currentUser.role === "Admin") &&
          (!requiredPermission || userPermissions.includes(requiredPermission));
        setIsAllowed(allowed);
      } catch (err) {
        console.error("Error fetching permissions:", err);
        setIsAllowed(false);
      } finally {
        setLoading(false);
      }
    };

    fetchPermissions();
  }, [token, currentUser, adminOnly, requiredPermission, setPermissions]);

  if (!token) return <Navigate to="/" replace />;
  if (loading) return <div>Loading...</div>;
  if (!isAllowed) return <Navigate to="/dashboard" replace />;

  return children;
}

export default ProtectedRoute;
